115	  if (tabId === 'support_master_management') {
116	    return (
117	      hasPermission(user, 'support_requests.read')
118	      || hasPermission(user, 'support_service_groups.read')
119	      || hasPermission(user, 'support_contact_positions.read')
120	    );
121	  }
122	
123	  const permission = TAB_PERMISSION_MAP[tabId];
124	  if (permission === undefined) {
125	    if (import.meta.env.DEV) {
126	      console.warn(`[Auth] Tab '${tabId}' missing from TAB_PERMISSION_MAP - denied`);
127	    }
128	
129	    return false;
130	  }
131	
132	  return hasPermission(user, permission);
